"use client";

import {
  Sequence,
  interpolate,
  useCurrentFrame,
  useVideoConfig,
} from "remotion";

export interface GlassCodeBlockProps {
  code?: string;
  title?: string;
  width?: number;
  height?: number;
  fontSize?: number;
  glassColor?: string;
  staggerFrames?: number;
  showTrafficLights?: boolean;
  /** The soft cyan/purple gradient glow behind the glass. On by default. */
  aura?: boolean;
  /**
   * Reveal the first line as a left-to-right typewriter (with a block cursor)
   * instead of the default fade-up; the remaining lines then stagger in only
   * after the first line finishes typing. Off by default.
   */
  typeFirstLine?: boolean;
  /** Typing speed (characters/second) when `typeFirstLine` is on. */
  firstLineCps?: number;
  speed?: number;
  className?: string;
}

/** Frames the first-line typewriter takes — exported so a caller can sync a
 *  camera move to the moment typing completes. */
export function firstLineTypeFrames(
  firstLine: string,
  firstLineCps: number,
  fps: number,
): number {
  return Math.ceil((firstLine.length / firstLineCps) * fps);
}

const FONT_MONO =
  "var(--font-geist-mono), ui-monospace, SFMono-Regular, monospace";

const DEFAULT_CODE = `import { motion } from "remotion";

// Generate a hero scene
export function Hero() {
  const frame = useCurrentFrame();
  const opacity = frame / 30;
  return <h1 style={{ opacity }}>Hello</h1>;
}`;

// Minimal regex tokenizer. NOT a real syntax highlighter — just enough to
// give the eye color anchors. Order matters: comments → strings → keywords.
const KEYWORDS = new Set([
  "import",
  "from",
  "export",
  "function",
  "const",
  "let",
  "var",
  "return",
  "if",
  "else",
  "for",
  "while",
  "new",
  "class",
  "extends",
  "default",
  "true",
  "false",
  "null",
  "undefined",
]);

type Token = {
  text: string;
  kind: "code" | "comment" | "string" | "keyword" | "number";
};

function tokenizeLine(line: string): Token[] {
  // Whole-line comment.
  const trimmed = line.trimStart();
  if (trimmed.startsWith("//")) {
    return [{ text: line, kind: "comment" }];
  }

  const tokens: Token[] = [];
  // Split keeping delimiters: words, strings, numbers, everything else.
  const re = /("[^"]*"|'[^']*'|`[^`]*`|\b\d+\b|\b[A-Za-z_$][\w$]*\b|[^\w"']+)/g;
  let match: RegExpExecArray | null;
  while ((match = re.exec(line)) !== null) {
    const t = match[0];
    const first = t[0];
    if (first === '"' || first === "'" || first === "`") {
      tokens.push({ text: t, kind: "string" });
    } else if (/^\d+$/.test(t)) {
      tokens.push({ text: t, kind: "number" });
    } else if (/^[A-Za-z_$][\w$]*$/.test(t) && KEYWORDS.has(t)) {
      tokens.push({ text: t, kind: "keyword" });
    } else {
      tokens.push({ text: t, kind: "code" });
    }
  }
  return tokens;
}

const TOKEN_COLORS: Record<Token["kind"], string> = {
  code: "#e4e4e7",
  comment: "#52525b",
  string: "#86efac",
  keyword: "#c4b5fd",
  number: "#fcd34d",
};

export function GlassCodeBlock({
  code = DEFAULT_CODE,
  title = "hero.tsx",
  width = 760,
  height = 460,
  fontSize = 16,
  glassColor = "rgba(10, 10, 10, 0.6)",
  staggerFrames = 4,
  showTrafficLights = true,
  aura = true,
  typeFirstLine = false,
  firstLineCps = 30,
  speed = 1,
  className,
}: GlassCodeBlockProps) {
  const { fps } = useVideoConfig();
  const lines = code.split("\n");
  // When the first line types, every later line waits until typing is done.
  const typeDur = typeFirstLine
    ? firstLineTypeFrames(lines[0] ?? "", firstLineCps, fps)
    : 0;

  return (
    <div
      className={className}
      style={{
        position: "absolute",
        inset: 0,
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
      }}
    >
      {/* Animated background hint behind the glass so the blur has something
          to chew on. Pure CSS — no extra deps. */}
      {aura && <BackdropAura />}

      {/* 1px gradient ring acting as a microborder */}
      <div
        style={{
          position: "relative",
          padding: 1,
          borderRadius: 16,
          background:
            "linear-gradient(180deg, rgba(255,255,255,0.18) 0%, rgba(255,255,255,0) 100%)",
          width,
          height,
          boxShadow: "0 50px 120px rgba(0,0,0,0.55)",
        }}
      >
        <div
          style={{
            width: "100%",
            height: "100%",
            borderRadius: 15,
            background: glassColor,
            backdropFilter: "blur(16px)",
            WebkitBackdropFilter: "blur(16px)",
            boxShadow: "inset 0 1px 0 rgba(255,255,255,0.06)",
            display: "flex",
            flexDirection: "column",
            overflow: "hidden",
            fontFamily: FONT_MONO,
          }}
        >
          {/* Chrome */}
          <div
            style={{
              height: 40,
              display: "flex",
              alignItems: "center",
              gap: 8,
              padding: "0 16px",
              borderBottom: "1px solid rgba(255,255,255,0.06)",
            }}
          >
            {showTrafficLights && (
              <>
                <Light color="#ff5f57" />
                <Light color="#febc2e" />
                <Light color="#28c840" />
              </>
            )}
            <div
              style={{
                flex: 1,
                textAlign: "center",
                color: "#a1a1aa",
                fontSize: 12,
                letterSpacing: "0.02em",
              }}
            >
              {title}
            </div>
          </div>

          {/* Code body */}
          <div
            style={{
              flex: 1,
              padding: "20px 24px",
              display: "flex",
              flexDirection: "column",
              gap: 4,
              fontSize,
              lineHeight: 1.55,
            }}
          >
            {lines.map((line, i) => {
              if (typeFirstLine && i === 0) {
                return (
                  <Sequence key={i} from={0} layout="none">
                    <TypedCodeLine
                      line={line}
                      index={i}
                      fontSize={fontSize}
                      cps={firstLineCps}
                      fps={fps}
                      speed={speed}
                    />
                  </Sequence>
                );
              }
              const baseFrom = typeFirstLine
                ? typeDur + (i - 1) * staggerFrames
                : i * staggerFrames;
              return (
                <Sequence
                  key={i}
                  from={Math.round(baseFrom / speed)}
                  layout="none"
                >
                  <CodeLine line={line} index={i} fontSize={fontSize} />
                </Sequence>
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );
}

function Light({ color }: { color: string }) {
  return (
    <div
      style={{
        width: 12,
        height: 12,
        borderRadius: "50%",
        background: color,
        opacity: 0.6,
      }}
    />
  );
}

function CodeLine({
  line,
  index,
  fontSize,
}: {
  line: string;
  index: number;
  fontSize: number;
}) {
  const frame = useCurrentFrame();
  const opacity = interpolate(frame, [0, 8], [0, 1], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
  });
  const ty = interpolate(frame, [0, 8], [4, 0], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
  });

  const tokens = tokenizeLine(line);
  // Render an empty line as a half-height spacer so blank lines still take
  // visual space without collapsing the gap.
  if (tokens.length === 0) {
    return <div style={{ height: fontSize * 0.8, opacity }} />;
  }
  return (
    <div
      style={{
        opacity,
        transform: `translateY(${ty}px)`,
        whiteSpace: "pre",
        display: "flex",
        gap: 0,
      }}
    >
      <span style={{ width: 28, color: "#3f3f46", userSelect: "none" }}>
        {String(index + 1).padStart(2, " ")}
      </span>
      <span>
        {tokens.map((t, i) => (
          <span key={i} style={{ color: TOKEN_COLORS[t.kind] }}>
            {t.text}
          </span>
        ))}
      </span>
    </div>
  );
}

function TypedCodeLine({
  line,
  index,
  fontSize,
  cps,
  fps,
  speed,
}: {
  line: string;
  index: number;
  fontSize: number;
  cps: number;
  fps: number;
  speed: number;
}) {
  const frame = useCurrentFrame() * speed;
  const len = line.length;
  const revealed = Math.floor(
    interpolate(frame, [0, (len / cps) * fps], [0, len], {
      extrapolateLeft: "clamp",
      extrapolateRight: "clamp",
    }),
  );
  const visible = line.substring(0, revealed);
  const done = revealed >= len;
  // 2 Hz blink at any framerate.
  const cursorOn = Math.floor((frame / fps) * 2) % 2 === 0;
  const tokens = tokenizeLine(visible);

  return (
    <div
      style={{
        whiteSpace: "pre",
        display: "flex",
        gap: 0,
        alignItems: "center",
      }}
    >
      <span style={{ width: 28, color: "#3f3f46", userSelect: "none" }}>
        {String(index + 1).padStart(2, " ")}
      </span>
      <span>
        {tokens.map((t, i) => (
          <span key={i} style={{ color: TOKEN_COLORS[t.kind] }}>
            {t.text}
          </span>
        ))}
        {!done && cursorOn && (
          <span
            style={{
              display: "inline-block",
              width: fontSize * 0.55,
              height: fontSize,
              background: "#e4e4e7",
              marginLeft: 1,
              transform: "translateY(2px)",
            }}
          />
        )}
      </span>
    </div>
  );
}

function BackdropAura() {
  // Slow, low-amplitude blob behind the glass so the backdrop blur has
  // perceptible content to refract.
  const frame = useCurrentFrame();
  const t = frame / 60;
  const x = 50 + Math.sin(t) * 20;
  const y = 50 + Math.cos(t * 0.7) * 15;
  return (
    <div
      style={{
        position: "absolute",
        inset: 0,
        pointerEvents: "none",
        background: `radial-gradient(circle at ${x}% ${y}%, rgba(56,189,248,0.22), transparent 50%), radial-gradient(circle at ${100 - x}% ${100 - y}%, rgba(168,85,247,0.18), transparent 55%)`,
      }}
    />
  );
}

import React, { type CSSProperties, type ReactNode } from "react";
import { AbsoluteFill, Easing, Series, interpolate, interpolateColors, spring, useCurrentFrame, useVideoConfig } from "remotion";
import { demoAsset } from "@/lib/demo-assets";
import {
  TransitionSeries,
  linearTiming,
  type TransitionPresentation,
  type TransitionPresentationComponentProps,
} from "@remotion/transitions";
import { loadFont as loadSans } from "@remotion/google-fonts/Manrope";
import { loadFont as loadPlayfair } from "@remotion/google-fonts/PlayfairDisplay";
import { loadFont as loadSourceSerif } from "@remotion/google-fonts/SourceSerif4";
import { loadFont as loadMono } from "@remotion/google-fonts/JetBrainsMono";
import { loadFont as loadAbril } from "@remotion/google-fonts/AbrilFatface";
import { loadFont as loadBebas } from "@remotion/google-fonts/BebasNeue";
import { loadFont as loadUrbanist } from "@remotion/google-fonts/Urbanist";

import { RemocnUIProvider } from "@/lib/remocn-ui";
import { Backdrop } from "@/components/remocn/backdrop";
import { GlassCodeBlock } from "@/components/remocn/glass-code-block";
import { SharedAxisZ } from "@/components/remocn/shared-axis-z";
import { RollingNumber } from "@/components/remocn/rolling-number";
import { TerminalCursorZoom } from "@/components/remocn/terminal-cursor-zoom";
import { useBlurInTransition } from "@/components/remocn/use-blur-in-transition";
import { BlurIn } from "@/components/remocn/blur-in";
import { CheckIcon, CopyIcon } from "lucide-react";

// ---------------------------------------------------------------------------
// Fonts. The whole point of a type product is to show the real typefaces — so
// every specimen here renders in its actual family, not a stand-in.
// ---------------------------------------------------------------------------
const { fontFamily: SANS_FAMILY } = loadSans("normal", {
  subsets: ["latin"],
  weights: ["400", "500", "600", "700"],
});
const { fontFamily: PLAYFAIR_FAMILY } = loadPlayfair("normal", {
  subsets: ["latin"],
  weights: ["500", "700", "800"],
});
const { fontFamily: SOURCE_SERIF_FAMILY } = loadSourceSerif("normal", {
  subsets: ["latin"],
  weights: ["400", "600"],
});
const { fontFamily: MONO_FAMILY } = loadMono("normal", {
  subsets: ["latin"],
  weights: ["400", "700"],
});
const { fontFamily: ABRIL_FAMILY } = loadAbril("normal", {
  subsets: ["latin"],
  weights: ["400"],
});
const { fontFamily: BEBAS_FAMILY } = loadBebas("normal", {
  subsets: ["latin"],
  weights: ["400"],
});
const { fontFamily: URBANIST_FAMILY } = loadUrbanist("normal", {
  subsets: ["latin"],
  weights: ["600", "800"],
});

const SANS = `${SANS_FAMILY}, -apple-system, BlinkMacSystemFont, sans-serif`;
const MONO = `${MONO_FAMILY}, ui-monospace, SFMono-Regular, monospace`;
const PLAYFAIR = `${PLAYFAIR_FAMILY}, Georgia, serif`;
const SOURCE_SERIF = `${SOURCE_SERIF_FAMILY}, Georgia, serif`;
const ABRIL = `${ABRIL_FAMILY}, Georgia, serif`;
const BEBAS = `${BEBAS_FAMILY}, Impact, sans-serif`;
const URBANIST = `${URBANIST_FAMILY}, sans-serif`;

// Editorial palette — warm ink + a single restrained gold accent.
const GOLD = "#e0a23c";
const INK = "#fafafa";
const MUTED = "rgba(250,250,250,0.62)";
const FAINT = "rgba(250,250,250,0.4)";

// ---------------------------------------------------------------------------
// Scene timings (frames @ 30fps), one per beat. Transitions overlap.
// ---------------------------------------------------------------------------
const S_INTRO = 140; //  three pain questions via shared-axis-z
const S_THREE = 48; //   "Three fonts." — the hook
const S_TRIO = 140; //   the editorial pairing — three real specimens
const S_INSTALL = 82; //  terminal-cursor-zoom install
const S_CODE = 132; //   generated CSS variables (GlassCodeBlock)
const S_COUNT = 88; //    78 curated pairings (rolling-number)
const S_WALL = 112; //   specimen wall across moods
const S_OUTRO = 112; //   wordmark + tagline + install pill

const T_ZOOM = 18; //  intro → three (punch in)
const T_X = 14; //      generic crossfade
const T_BLUR = 16; //   trio → install (background clash)
const T_OUT = 20; //    wall → outro

export const FONTTRIO_DURATION =
  S_INTRO +
  S_THREE +
  S_TRIO +
  S_INSTALL +
  S_CODE +
  S_COUNT +
  S_WALL +
  S_OUTRO -
  (T_ZOOM + T_X + T_BLUR + T_X + T_X + T_X + T_OUT);

// ---------------------------------------------------------------------------
// Reveal — blur-in wrapper driven by useBlurInTransition.
// ---------------------------------------------------------------------------
const Reveal: React.FC<{
  children: ReactNode;
  delay?: number;
  distance?: number;
  blur?: number;
  duration?: number;
  display?: CSSProperties["display"];
}> = ({
  children,
  delay = 0,
  distance = 16,
  blur = 10,
  duration = 20,
  display = "block",
}) => {
  const style = useBlurInTransition(
    [{ at: delay, state: "revealed", duration }],
    { direction: "up", distance, blur },
  );
  return (
    <BlurIn style={style} display={display}>
      {children}
    </BlurIn>
  );
};

// ---------------------------------------------------------------------------
// Mark — inline marker swipe behind a phrase.
// ---------------------------------------------------------------------------
const Mark: React.FC<{
  children: string;
  color?: string;
  startFrame?: number;
}> = ({ children, color = GOLD, startFrame = 8 }) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();
  const scaleX = spring({
    frame: frame - startFrame,
    fps,
    config: { damping: 15, mass: 0.8 },
  });
  const textColor = interpolateColors(
    interpolate(scaleX, [0.45, 0.85], [0, 1], {
      extrapolateLeft: "clamp",
      extrapolateRight: "clamp",
    }),
    [0, 1],
    [INK, "#0a0a0a"],
  );
  return (
    <span
      style={{
        position: "relative",
        display: "inline-block",
        whiteSpace: "nowrap",
      }}
    >
      <span
        aria-hidden
        style={{
          position: "absolute",
          inset: "-0.02em -0.12em",
          background: color,
          borderRadius: 6,
          transformOrigin: "left center",
          transform: `scaleX(${scaleX})`,
          zIndex: 0,
        }}
      />
      <span style={{ position: "relative", zIndex: 1, color: textColor }}>
        {children}
      </span>
    </span>
  );
};

// Small "trio" mark — three type-weight bars, the middle one gold.
const TrioMark: React.FC<{ size?: number }> = ({ size = 60 }) => (
  <svg width={size} height={size} viewBox="0 0 24 24" fill="none">
    <rect x={3} y={4} width={3.4} height={16} rx={1.7} fill={INK} />
    <rect x={10.3} y={4} width={3.4} height={16} rx={1.7} fill={GOLD} />
    <rect x={17.6} y={4} width={3.4} height={16} rx={1.7} fill={INK} />
  </svg>
);

// ===========================================================================
// Scene 1 — Intro. Three setup-the-pain questions, each via shared-axis-z.
// ===========================================================================
const Q1 = "Hand-picking fonts for every project?";
const Q2 = "Wiring CSS variables by hand?";
const Q3 = "Rebuilding the type scale each time?";

const IntroScene: React.FC = () => (
  <AbsoluteFill style={{ padding: "0 90px" }}>
    <Series>
      <Series.Sequence durationInFrames={42} layout="none">
        <SharedAxisZ
          fromText=""
          toText={Q1}
          fontSize={42}
          fontWeight={600}
          color={"#FFFFFF"}
        />
      </Series.Sequence>
      <Series.Sequence durationInFrames={46} layout="none">
        <SharedAxisZ
          fromText={Q1}
          toText={Q2}
          fontSize={42}
          fontWeight={600}
          color={"#FFFFFF"}
        />
      </Series.Sequence>
      <Series.Sequence durationInFrames={52} layout="none">
        <SharedAxisZ
          fromText={Q2}
          toText={Q3}
          fontSize={42}
          fontWeight={600}
          color={"#FFFFFF"}
        />
      </Series.Sequence>
    </Series>
  </AbsoluteFill>
);

// ===========================================================================
// Scene 2 — The hook. "Three fonts." settles hard and centered.
// ===========================================================================
const ThreeScene: React.FC = () => (
  <AbsoluteFill style={{ alignItems: "center", justifyContent: "center" }}>
    <SharedAxisZ
      fromText={""}
      toText={"Three fonts."}
      fontSize={130}
      fontWeight={700}
      color={"#FFFFFF"}
    />
  </AbsoluteFill>
);

// ===========================================================================
// Scene 3 — The editorial pairing. One pairing, three roles — each rendered in
// its real typeface so the viewer reads the actual fonts.
// ===========================================================================
const TrioRow: React.FC<{
  role: string;
  name: string;
  family: string;
  cssVar: string;
  nameSize: number;
  delay: number;
  divider?: boolean;
}> = ({ role, name, family, cssVar, nameSize, delay, divider = true }) => (
  <Reveal delay={delay} distance={22} blur={10} duration={20}>
    <div
      style={{
        display: "flex",
        alignItems: "flex-end",
        justifyContent: "space-between",
        gap: 24,
        padding: "20px 0",
        borderTop: divider ? "1px solid rgba(250,250,250,0.1)" : "none",
      }}
    >
      <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
        <span
          style={{
            fontFamily: SANS,
            fontSize: 14,
            fontWeight: 600,
            color: GOLD,
          }}
        >
          {role}
        </span>
        <span
          style={{
            fontFamily: family,
            fontSize: nameSize,
            color: INK,
            lineHeight: 1,
          }}
        >
          {name}
        </span>
      </div>
      <span style={{ fontFamily: MONO, fontSize: 15, color: FAINT }}>
        {cssVar}
      </span>
    </div>
  </Reveal>
);

const TrioScene: React.FC = () => (
  <AbsoluteFill
    style={{
      alignItems: "center",
      justifyContent: "center",
      flexDirection: "column",
      gap: 26,
    }}
  >
    <Reveal delay={2} distance={16} blur={10}>
      <div
        style={{ display: "flex", alignItems: "center", gap: 14 }}
      >
        <span
          style={{
            fontFamily: MONO,
            fontSize: 14,
            color: GOLD,
            padding: "5px 12px",
            borderRadius: 999,
            border: `1px solid ${GOLD}55`,
            background: `${GOLD}1a`,
          }}
        >
          editorial
        </span>
        <h2
          style={{
            margin: 0,
            fontFamily: SANS,
            fontWeight: 600,
            fontSize: 34,
            color: INK,
          }}
        >
          One pairing, three roles
        </h2>
      </div>
    </Reveal>
    <Reveal delay={8} distance={36} blur={14} duration={22}>
      <div
        style={{
          width: 740,
          padding: "12px 40px 24px",
          borderRadius: 20,
          background: "rgba(10,10,10,0.55)",
          border: `1px solid ${GOLD}3a`,
          boxShadow: "0 20px 50px rgba(0,0,0,0.45)",
        }}
      >
        <TrioRow
          role="Heading"
          name="Playfair Display"
          family={PLAYFAIR}
          cssVar="--font-heading"
          nameSize={46}
          delay={16}
          divider={false}
        />
        <TrioRow
          role="Body"
          name="Source Serif 4"
          family={SOURCE_SERIF}
          cssVar="--font-body"
          nameSize={38}
          delay={24}
        />
        <TrioRow
          role="Mono"
          name="JetBrains Mono"
          family={MONO}
          cssVar="--font-mono"
          nameSize={30}
          delay={32}
        />
      </div>
    </Reveal>
  </AbsoluteFill>
);

// ===========================================================================
// Scene 4 — Install. terminal-cursor-zoom dollies across the typed command.
// ===========================================================================
const InstallScene: React.FC = () => (
  <AbsoluteFill>
    <TerminalCursorZoom
      command="npx shadcn add @fonttrio/editorial"
      title="~/my-app"
      fontSize={22}
      zoom={2.4}
      charsPerFrame={1}
    />
  </AbsoluteFill>
);

// ===========================================================================
// Scene 5 — What lands in your project: the generated CSS variables.
// ===========================================================================
const CSS_EXAMPLE = `/* app/globals.css — added by Fonttrio */
:root {
  --font-heading: var(--font-playfair-display);
  --font-body: var(--font-source-serif-4);
  --font-mono: var(--font-jetbrains-mono);
}

h1, h2, h3 {
  font-family: var(--font-heading);
  font-weight: 700;
}

p {
  font-family: var(--font-body);
  line-height: 1.65;
}`;

const CodeScene: React.FC = () => (
  <AbsoluteFill
    style={{
      alignItems: "center",
      justifyContent: "center",
      flexDirection: "column",
      gap: 26,
    }}
  >
    <Reveal delay={2} distance={16} blur={10}>
      <h2
        style={{
          margin: 0,
          fontFamily: SANS,
          fontWeight: 600,
          fontSize: 38,
          color: INK,
          textAlign: "center",
        }}
      >
        Variables,{" "}
        <Mark color={GOLD} startFrame={12}>
          wired for you
        </Mark>
      </h2>
